{"type":"tool_use","id":"call_e645b805089f4bbf810b185f","name":"Write","input":{"file_path":"/Users/xin/auto-skills/.claude/worktrees/worker-task-f/src/query-api.ts","content":"import * as fs from 'fs';
import * as path from 'path';

export interface QueryResult {
  symbol: string;
  locations: Location[];
}

export interface Location {
  file: string;
  line: number;
  column?: number;
  context: string;
  kind: 'definition' | 'reference' | 'call';
}

function findFiles(dir: string, exts: string[]): string[] {
  if (!fs.existsSync(dir)) return [];
  let results: string[] = [];
  const entries = fs.readdirSync(dir, { withFileTypes: true });
  for (const entry of entries) {
    if (entry.name.startsWith('.') || entry.name === 'node_modules') continue;
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) {
      results = results.concat(findFiles(full, exts));
    } else if (exts.some(ext => entry.name.endsWith(ext))) {
      results.push(full);
    }
  }
  return results;
}

const EXTENSIONS = ['.ts', '.tsx', '.js', '.jsx', '.mjs', '.cjs'];

function searchInFile(filePath: string, pattern: RegExp, kind: 'definition' | 'reference' | 'call'): Location[] {
  const content = fs.readFileSync(filePath, 'utf-8');
  const lines = content.split('\n');
  const locations: Location[] = [];
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    if (pattern.test(line)) {
      const col = line.search(pattern);
      const start = Math.max(0, col - 20);
      const end = Math.min(line.length, col + pattern.toString().length + 40);
      locations.push({
        file: filePath,
        line: i + 1,
        column: col,
        context: (start > 0 ? '...' : '') + line.slice(start, end) + (end < line.length ? '...' : ''),
        kind,
      });
    }
  }
  return locations;
}

export function findDefinition(symbol: string, rootDir: string): QueryResult {
  const defPatterns = [
    new RegExp(`(?:function|class|const|let|var|interface|type|enum|export\\s+function|export\\s+class|export\\s+const|export\\s+default)\\s+${escapeRegex(symbol)}\\b`),
    new RegExp(`${escapeRegex(symbol)}\\s*[=:]\\s*(?:function|class|\\(|\\{)`),
  ];
  const files = findFiles(rootDir, EXTENSIONS);
  const locations: Location[] = [];
  for (const file of files) {
    for (const pat of defPatterns) {
      locations.push(...searchInFile(file, pat, 'definition'));
    }
  }
  return { symbol, locations };
}

export function findReferences(symbol: string, rootDir: string): QueryResult {
  const pattern = new RegExp(`\\b${escapeRegex(symbol)}\\b`);
  const files = findFiles(rootDir, EXTENSIONS);
  const locations: Location[] = [];
  for (const file of files) {
    locations.push(...searchInFile(file, pattern, 'reference'));
  }
  return { symbol, locations };
}

export function findCallers(funcName: string, rootDir: string): QueryResult {
  const callPattern = new RegExp(`\\b${escapeRegex(funcName)}\\s*\\(`);
  const files = findFiles(rootDir, EXTENSIONS);
  const locations: Location[] = [];
  for (const file of files) {
    locations.push(...searchInFile(file, callPattern, 'call'));
  }
  return { symbol: funcName, locations };
}

function escapeRegex(str: string): string {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

export function formatResult(result: QueryResult): string {
  if (result.locations.length === 0) {
    return `No results found for: ${result.symbol}\n`;
  }
  const parts: string[] = [];
  parts.push(`Found ${result.locations.length} result(s) for: ${result.symbol}\n`);
  parts.push('─'.repeat(60));
  for (const loc of result.locations) {
    parts.push(`  [${loc.kind}] ${loc.file}:${loc.line}`);
    if (loc.column !== undefined && loc.column >= 0) {
      parts.push(`  ${' '.repeat(loc.column + 4)}^`);
    }
    parts.push(`  ${loc.context.trim()}`);
    parts.push('');
  }
  return parts.join('\n');
}
