import { findDefinition, findReferences, findCallers, formatResult } from '../query-api';
import * as path from 'path';

const USAGE = `
fg-query — command-line code query tool

Usage:
  fg-query find-definition <symbol>    Find where a symbol is defined
  fg-query find-references <symbol>    Find all references to a symbol
  fg-query find-callers <function>     Find all call sites of a function
  fg-query help                        Show this help message

Options:
  --dir <path>   Root directory to search (default: current directory)
`;

function main() {
  const args = process.argv.slice(2);
  if (args.length === 0 || args[0] === 'help' || args[0] === '--help' || args[0] === '-h') {
    process.stdout.write(USAGE);
    process.exit(0);
  }

  const dirIdx = args.indexOf('--dir');
  let rootDir = process.cwd();
  if (dirIdx !== -1 && args[dirIdx + 1]) {
    rootDir = path.resolve(args[dirIdx + 1]);
    args.splice(dirIdx, 2);
  }

  const command = args[0];
  const symbol = args[1];

  if (!symbol) {
    process.stderr.write(`Error: missing <symbol> argument for "${command}"\n`);
    process.stderr.write(USAGE);
    process.exit(1);
  }

  let result;
  switch (command) {
    case 'find-definition':
      result = findDefinition(symbol, rootDir);
      break;
    case 'find-references':
      result = findReferences(symbol, rootDir);
      break;
    case 'find-callers':
      result = findCallers(symbol, rootDir);
      break;
    default:
      process.stderr.write(`Error: unknown command "${command}"\n`);
      process.stderr.write(USAGE);
      process.exit(1);
  }

  process.stdout.write(formatResult(result));
}

main();
"}}

